INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 7, "キャル", 0.0, 0, "2030/12/17 14:59:59", 1, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", 106001, 1, "2015/12/17 15:00:00", 0.0, 7001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 7, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", 105901, 1, "2015/12/17 15:00:00", 0.0, 7002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 7, "ペコリーヌ", 0.0, 0, "2030/12/17 14:59:59", 1, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", 105801, 1, "2015/12/17 15:00:00", 0.0, 7003);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 10, "ペコリーヌ", 0.0, 0, "2030/12/17 14:59:59", 1, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", 105801, 1, "2015/12/17 15:00:00", 0.0, 10001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 10, "キャル", 0.0, 0, "2030/12/17 14:59:59", 1, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", 106001, 1, "2015/12/17 15:00:00", 0.0, 10002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 10, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", 105901, 1, "2015/12/17 15:00:00", 0.0, 10003);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 2104010, 2, 10, "シェフィ", 0.0, 0, "2030/12/17 14:59:59", 1, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", 106401, 1, "2015/12/17 15:00:00", 0.0, 10004);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, 0, 1, 12, "ペコリーヌ", 0.0, 0, "2030/12/17 14:59:59", 1, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", 105801, 1, "2015/12/17 15:00:00", 0.0, 12001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 13, "キャル", 0.0, 0, "2030/12/17 14:59:59", 1, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", 106001, 1, "2015/12/17 15:00:00", 0.0, 13001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 13, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", 105901, 1, "2015/12/17 15:00:00", 0.0, 13002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 2104010, 2, 13, "シェフィ", 0.0, 0, "2030/12/17 14:59:59", 1, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", 106401, 1, "2015/12/17 15:00:00", 0.0, 13003);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 13, "ペコリーヌ", 0.0, 0, "2030/12/17 14:59:59", 1, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", 105801, 1, "2015/12/17 15:00:00", 0.0, 13004);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 14, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", 105901, 1, "2015/12/17 15:00:00", 0.0, 14001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 2104010, 2, 14, "シェフィ", 0.0, 0, "2030/12/17 14:59:59", 1, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", 106401, 1, "2015/12/17 15:00:00", 0.0, 14002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 14, "ペコリーヌ", 0.0, 0, "2030/12/17 14:59:59", 1, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", 105801, 1, "2015/12/17 15:00:00", 0.0, 14003);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 14, "キャル", 0.0, 0, "2030/12/17 14:59:59", 1, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", 106001, 1, "2015/12/17 15:00:00", 0.0, 14004);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, 0, 1, 15, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", 105901, 1, "2015/12/17 15:00:00", 0.0, 15001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 2104010, 2, 16, "シェフィ", 0.0, 0, "2030/12/17 14:59:59", 1, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", 106401, 1, "2015/12/17 15:00:00", 0.0, 16001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 16, "ペコリーヌ", 0.0, 0, "2030/12/17 14:59:59", 1, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", 105801, 1, "2015/12/17 15:00:00", 0.0, 16002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 16, "キャル", 0.0, 0, "2030/12/17 14:59:59", 1, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", 106001, 1, "2015/12/17 15:00:00", 0.0, 16003);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 16, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", 105901, 1, "2015/12/17 15:00:00", 0.0, 16004);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 17, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", 105901, 1, "2015/12/17 15:00:00", 0.0, 17002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 25, "キャル", 0.0, 0, "2030/12/17 14:59:59", 1, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", 106001, 1, "2015/12/17 15:00:00", 0.0, 17004);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 25, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", 105901, 1, "2015/12/17 15:00:00", 0.0, 17005);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 2104010, 2, 25, "シェフィ", 0.0, 0, "2030/12/17 14:59:59", 1, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", 106401, 1, "2015/12/17 15:00:00", 0.0, 17006);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 25, "ペコリーヌ", 0.0, 0, "2030/12/17 14:59:59", 1, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", 105801, 1, "2015/12/17 15:00:00", 0.0, 17007);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 18, "カリン", 0.0, 0, "2030/12/17 14:59:59", 1, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", 190801, 1, "2015/12/17 15:00:00", 0.0, 18001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 18, "カリン", 0.0, 0, "2030/12/17 14:59:59", 2, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", 190801, 1, "2015/12/17 15:00:00", 0.0, 18002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, 0, 1, 19, "カリン", 0.0, 0, "2030/12/17 14:59:59", 3, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", 190801, 1, "2015/12/17 15:00:00", 0.0, 19001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, 0, 1, 19, "カリン", 0.0, 0, "2030/12/17 14:59:59", 4, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", 190801, 1, "2015/12/17 15:00:00", 0.0, 19002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, 0, 1, 20, "カリン", 0.0, 0, "2030/12/17 14:59:59", 5, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", 190801, 1, "2015/12/17 15:00:00", 0.0, 20001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, 0, 1, 20, "カリン", 0.0, 0, "2030/12/17 14:59:59", 6, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", 190801, 1, "2015/12/17 15:00:00", 0.0, 20002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 21, "キャル", 0.0, 0, "2030/12/17 14:59:59", 1, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", 106001, 1, "2015/12/17 15:00:00", 0.0, 21001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 21, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", 105901, 1, "2015/12/17 15:00:00", 0.0, 21002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 2104010, 2, 21, "シェフィ", 0.0, 0, "2030/12/17 14:59:59", 1, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", 106401, 1, "2015/12/17 15:00:00", 0.0, 21003);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 21, "ペコリーヌ", 0.0, 0, "2030/12/17 14:59:59", 1, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", 105801, 1, "2015/12/17 15:00:00", 0.0, 21004);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, 0, 1, 22, "カリン", 0.0, 0, "2030/12/17 14:59:59", 1, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", 190801, 1, "2015/12/17 15:00:00", 0.0, 22001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, 0, 1, 22, "カリン", 0.0, 0, "2030/12/17 14:59:59", 2, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", 190801, 1, "2015/12/17 15:00:00", 0.0, 22002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, 0, 1, 23, "カリン", 0.0, 0, "2030/12/17 14:59:59", 3, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", 190801, 1, "2015/12/17 15:00:00", 0.0, 23001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, 0, 1, 23, "カリン", 0.0, 0, "2030/12/17 14:59:59", 4, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", 190801, 1, "2015/12/17 15:00:00", 0.0, 23002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, 0, 1, 24, "エリコ（バレンタイン）", 4.08, 10011, "2030/12/17 14:59:59", 1, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", 109001, 2, "2019/01/31 12:00:00", 8.0, 24001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, 0, 1, 24, "エリコ（バレンタイン）", 5.0, 10011, "2030/12/17 14:59:59", 2, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", 109001, 2, "2019/01/31 12:00:00", 8.0, 24002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, 0, 1, 24, "エリコ（バレンタイン）", 10.11, 10011, "2030/12/17 14:59:59", 3, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", 109001, 2, "2019/01/31 12:00:00", 8.0, 24003);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, 0, 1, 24, "エリコ（バレンタイン）", 4.0, 10011, "2030/12/17 14:59:59", 4, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", 109001, 2, "2019/01/31 12:00:00", 8.0, 24004);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, 0, 1, 24, "エリコ（バレンタイン）", 6.0, 10011, "2030/12/17 14:59:59", 5, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", 109001, 2, "2019/01/31 12:00:00", 8.0, 24005);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, 0, 1, 24, "エリコ（バレンタイン）", 0.0, 10011, "2030/12/17 14:59:59", 6, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", 109002, 1, "2019/01/31 12:00:00", 0.0, 24006);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, 0, 1, 24, "エリコ（バレンタイン）", 0.0, 10011, "2030/12/17 14:59:59", 7, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", 109002, 1, "2019/01/31 12:00:00", 0.0, 24007);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, 0, 1, 24, "エリコ（バレンタイン）", 0.0, 10011, "2030/12/17 14:59:59", 8, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", 109002, 1, "2019/01/31 12:00:00", 0.0, 24008);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, 0, 1, 24, "エリコ（バレンタイン）", 0.0, 10011, "2030/12/17 14:59:59", 9, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", 109002, 1, "2019/01/31 12:00:00", 0.0, 24009);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, 0, 1, 24, "エリコ（バレンタイン）", 0.0, 10011, "2030/12/17 14:59:59", 10, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", 109002, 1, "2019/01/31 12:00:00", 0.0, 24010);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, 0, 1, 24, "シズル（バレンタイン）", 2.12, 10011, "2030/12/17 14:59:59", 1, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", 109101, 2, "2019/01/31 12:00:00", 8.0, 24011);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, 0, 5, 24, "シズル（バレンタイン）", 4.19, 10011, "2030/12/17 14:59:59", 2, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", 109101, 2, "2019/01/31 12:00:00", 8.0, 24012);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, 0, 2, 24, "シズル（バレンタイン）", 2.3, 10011, "2030/12/17 14:59:59", 3, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", 109101, 4, "2019/01/31 12:00:00", 8.0, 24013);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, 0, 1, 24, "シズル（バレンタイン）", 0.0, 10011, "2030/12/17 14:59:59", 4, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", 109102, 1, "2019/01/31 12:00:00", 0.0, 24014);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, 0, 5, 24, "シズル（バレンタイン）", 5.23, 10011, "2030/12/17 14:59:59", 5, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", 109101, 2, "2019/01/31 12:00:00", 8.0, 24015);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, 0, 1, 24, "シズル（バレンタイン）", 0.0, 10011, "2030/12/17 14:59:59", 6, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", 109102, 1, "2019/01/31 12:00:00", 0.0, 24016);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, 0, 1, 24, "シズル（バレンタイン）", 5.01, 10011, "2030/12/17 14:59:59", 7, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", 109101, 2, "2019/01/31 12:00:00", 8.0, 24017);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, 0, 1, 24, "シズル（バレンタイン）", 0.0, 10011, "2030/12/17 14:59:59", 8, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", 109102, 1, "2019/01/31 12:00:00", 0.0, 24018);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, 0, 1, 24, "シズル（バレンタイン）", 0.0, 10011, "2030/12/17 14:59:59", 9, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", 109102, 1, "2019/01/31 12:00:00", 0.0, 24019);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, 0, 1, 24, "シズル（バレンタイン）", 0.0, 10011, "2030/12/17 14:59:59", 10, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", 109102, 1, "2019/01/31 12:00:00", 0.0, 24020);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 2104010, 2, 26, "シェフィ", 0.0, 0, "2030/12/17 14:59:59", 1, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", 106401, 1, "2015/12/17 15:00:00", 0.0, 26001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 26, "ペコリーヌ", 0.0, 0, "2030/12/17 14:59:59", 1, "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", 105801, 1, "2015/12/17 15:00:00", 0.0, 26002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 26, "キャル", 0.0, 0, "2030/12/17 14:59:59", 1, "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", 106001, 1, "2015/12/17 15:00:00", 0.0, 26003);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 26, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", 105901, 1, "2015/12/17 15:00:00", 0.0, 26004);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 2104010, 2, 27, "シェフィ", 0.0, 0, "2030/12/17 14:59:59", 1, "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", 106401, 1, "2015/12/17 15:00:00", 0.0, 27001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 27, "ペコリーヌ", 0.0, 0, "2030/12/17 14:59:59", 1, "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", 105801, 1, "2015/12/17 15:00:00", 0.0, 27002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 27, "キャル", 0.0, 0, "2030/12/17 14:59:59", 1, "ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", 106001, 1, "2015/12/17 15:00:00", 0.0, 27003);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 27, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, "こちらにさらなる力を得る\nためのアイテムが眠っている\nようです。主さま、どこから\n挑戦いたしましょう。", 105901, 1, "2015/12/17 15:00:00", 0.0, 27004);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 28, "カリン", 0.0, 0, "2030/12/17 14:59:59", 1, "ようこそ！\n皆さんの素敵な出会いを\nギルド管理協会が\nお手伝いします！", 190801, 1, "2019/09/24 15:00:00", 0.0, 28001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 28, "カリン", 0.0, 0, "2030/12/17 14:59:59", 2, "ギルド管理協会です\nフレンドに関しては\nこちらでご確認ください", 190801, 1, "2019/09/24 15:00:00", 0.0, 28002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, 0, 1, 29, "カリン", 0.0, 0, "2030/12/17 14:59:59", 3, "こちらがフレンドの\n皆さんです\n素敵な関係を\n築いてくださいね！", 190801, 1, "2019/09/24 15:00:00", 0.0, 29001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, 0, 1, 29, "カリン", 0.0, 0, "2030/12/17 14:59:59", 4, "こちらの一覧で\nフレンドのプロフィールを\n確認できますよ", 190801, 1, "2019/09/24 15:00:00", 0.0, 29002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, 0, 1, 30, "カリン", 0.0, 0, "2030/12/17 14:59:59", 5, "フレンド管理は\nこちらになります\n新しいフレンドとの出会いを\n楽しんでくださいね！", 190801, 1, "2019/09/24 15:00:00", 0.0, 30001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, 0, 1, 30, "カリン", 0.0, 0, "2030/12/17 14:59:59", 6, "フレンドの申請や\n承認ができますよ\nどうぞ、良き交流を！", 190801, 1, "2019/09/24 15:00:00", 0.0, 30002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, 0, 1, 31, "カリン", 0.0, 0, "2030/12/17 14:59:59", 7, "バトルをして力比べを\nしてみましょう！\n実力が試されますね、\n頑張ってください！", 190801, 1, "2019/10/31 12:00:00", 0.0, 31001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, 0, 1, 31, "カリン", 0.0, 0, "2030/12/17 14:59:59", 8, "気になるパーティと\nバトルをしてみましょう！\nどちらが勝利するのか、\n私も楽しみにしていますね", 190801, 1, "2019/10/31 12:00:00", 0.0, 31002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, 0, 1, 32, "カリン", 0.0, 0, "2020/01/04 4:59:59", 1, "ルーキーの皆さんのために\n特別なミッションを\nご用意いたしました！\nぜひ、挑戦してください！", 190801, 1, "2019/12/20 5:00:00", 0.0, 32001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, 0, 1, 32, "カリン", 0.0, 0, "2020/01/04 4:59:59", 2, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", 190801, 1, "2019/12/20 5:00:00", 0.0, 32002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, 0, 1, 33, "カリン", 0.0, 0, "2020/01/04 4:59:59", 3, "フレンドになって\n初心者の方を応援しましょう！\n素敵な報酬が待っていますよ！", 190801, 1, "2019/12/20 5:00:00", 0.0, 33001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, 0, 1, 33, "カリン", 0.0, 0, "2020/01/04 4:59:59", 4, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", 190801, 1, "2019/12/20 5:00:00", 0.0, 33002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, 0, 1, 34, "カリン", 0.0, 0, "2020/01/10 11:59:59", 5, "お疲れ様でした！\nミッションの報酬の受け取りは\nこちらからできますよ！", 190801, 1, "2020/01/04 5:00:00", 0.0, 34001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, 0, 1, 34, "カリン", 0.0, 0, "2020/01/10 11:59:59", 6, "ミッション報酬の受け取りは\nこちら！\n受け取り漏れの無いように\n気を付けてくださいね！", 190801, 1, "2020/01/04 5:00:00", 0.0, 34002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-458.0, 0, 1, 38, "ペコリーヌ", 5.3, 0, "2030/12/17 14:59:59", 1, "過去のストーリーイベントを\n楽しめちゃいますよ！\n遊んだことのないものがあれば\n一緒にやってみましょう♪", 105801, 2, "2015/12/17 15:00:00", 0.0, 38001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-458.0, 0, 1, 38, "ペコリーヌ", 6.5, 0, "2030/12/17 14:59:59", 2, "これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", 105801, 2, "2015/12/17 15:00:00", 0.0, 38002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (9999.0, 0, 3, 39, "ペコリーヌ", 0.0, 0, "2020/04/08 23:59:59", 0, "", 105801, 3, "2020/04/01", 9999.0, 39005);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, 0, 1, 40, "カリン", 0.0, 0, "2030/12/17 14:59:59", 2, "これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", 190801, 1, "2015/12/17 15:00:00", 0.0, 40001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 2104010, 1, 41, "シェフィ", 0.0, 0, "2030/12/17 14:59:59", 1, "ここでは腕試しが\nできるんですって。\n自分の実力を測るのに、\nちょうどよさそうね。", 106401, 1, "2015/12/17 15:00:00", 0.0, 41001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 41, "ペコリーヌ", 0.0, 0, "2030/12/17 14:59:59", 1, "ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", 105801, 1, "2015/12/17 15:00:00", 0.0, 41002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 41, "キャル", 0.0, 0, "2030/12/17 14:59:59", 1, "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", 106001, 1, "2015/12/17 15:00:00", 0.0, 41003);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 41, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", 105901, 1, "2015/12/17 15:00:00", 0.0, 41004);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, 0, 1, 42, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, "訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", 105901, 1, "2015/12/17 15:00:00", 0.0, 42001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, 2104010, 1, 42, "シェフィ", 0.0, 0, "2030/12/17 14:59:59", 1, "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", 106401, 1, "2015/12/17 15:00:00", 0.0, 42002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, 0, 1, 42, "ペコリーヌ", 0.0, 0, "2030/12/17 14:59:59", 1, "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", 105801, 1, "2015/12/17 15:00:00", 0.0, 42003);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, 0, 1, 42, "キャル", 0.0, 0, "2030/12/17 14:59:59", 1, "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", 106001, 1, "2015/12/17 15:00:00", 0.0, 42004);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 43, "ペコリーヌ", 0.0, 0, "2030/12/17 14:59:59", 1, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", 105801, 1, "2015/12/17 15:00:00", 0.0, 43001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 43, "コッコロ", 0.0, 0, "2030/12/17 14:59:59", 1, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", 105901, 1, "2015/12/17 15:00:00", 0.0, 43002);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, 0, 1, 43, "キャル", 0.0, 0, "2030/12/17 14:59:59", 1, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", 106001, 1, "2015/12/17 15:00:00", 0.0, 43003);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, 0, 1, 44, "アメス", 0.0, 0, "2030/12/17 14:59:59", 1, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", 123001, 1, "2015/12/17 15:00:00", 0.0, 43004);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, 0, 1, 44, "アメス", 0.0, 0, "2030/12/17 14:59:59", 2, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", 123001, 1, "2015/12/17 15:00:00", 0.0, 43005);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, 0, 1, 45, "アメス", 5.79, 0, "2030/12/17 14:59:59", 3, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", 123001, 2, "2015/12/17 15:00:00", 0.0, 43006);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-371.5, 0, 1, 46, "アメス", 0.0, 0, "2030/12/17 14:59:59", 1, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", 123001, 1, "2015/12/17 15:00:00", 0.0, 46001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, 0, 2, 47, "シズル", 0.0, 0, "2030/12/17 14:59:59", 1, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", 104901, 2, "2015/12/17 15:00:00", 0.0, 47001);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, 0, 1, 47, "リノ", 9.32, 0, "2030/12/17 14:59:59", 1, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", 101101, 2, "2015/12/17 15:00:00", 0.0, 47002);
